 1	import { ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
 2	import { Text } from '@patternfly/react-core';
 3	import * as React from 'react';
 4	import { TopologyMetricPeer } from '../../../api/loki';
 5	
 6	export interface PeerResourceLinkProps {
 7	  peer: TopologyMetricPeer;
 8	}
 9	
10	// Map of resource kinds that need explicit group-version-kind string
11	const customResourceGVK: { [kind: string]: string } = {
12	  Gateway: 'gateway.networking.k8s.io~v1~Gateway'
13	};
14	
15	export const PeerResourceLink: React.FC<PeerResourceLinkProps> = ({ peer }) => {
16	  const name = peer.getDisplayName(false, false);
17	  if (name) {
18	    if (peer.resourceKind) {
19	      const gvkString = customResourceGVK[peer.resourceKind];
20	      // Use group~version~kind format for custom resources, or plain kind for standard resources
21	      const kind = gvkString || peer.resourceKind;
22	      return <ResourceLink inline={true} kind={kind} name={name} namespace={peer.namespace} />;
23	    } else {
24	      return <Text component="p">{name}</Text>;
25	    }
26	  }
27	  return null;
28	};

